import { CreateSupplierSchema, CreateProductSchema, CreateTaxonomySchema } from './index';

/* eslint-disable no-console */
console.log('Running Schema Validation Tests...');

const errors: string[] = [];

// 1. Valid Supplier
const validSupplier = {
  name: 'Home Depot',
  website: 'https://homedepot.com',
  contact_info: { phone: '555-0199' }
};
const r1 = CreateSupplierSchema.safeParse(validSupplier);
if (!r1.success) errors.push('Failed to parse valid supplier: ' + JSON.stringify(r1.error));

// 2. Invalid Supplier (Product missing name)
const invalidSupplier = {
  website: 'bad-supplier'
};
const r2 = CreateSupplierSchema.safeParse(invalidSupplier);
if (r2.success) errors.push('Incorrectly accepted invalid supplier (missing name)');

// 3. Valid Product
const validProduct = {
  supplier_id: '123e4567-e89b-12d3-a456-426614174000',
  subject_key: 'gas_stove',
  name: 'Viking 3000',
  unit_price: 1200.50,
  attributes: { finish: 'stainless' }
};
const r3 = CreateProductSchema.safeParse(validProduct);
if (!r3.success) errors.push('Failed to parse valid product: ' + JSON.stringify(r3.error));

// 4. Valid Taxonomy
const validTaxonomy = {
    version: '1.0.0',
    data: { trades: { painting: {} } },
    is_active: true
};
const r4 = CreateTaxonomySchema.safeParse(validTaxonomy);
if (!r4.success) errors.push('Failed to parse valid taxonomy: ' + JSON.stringify(r4.error));

if (errors.length > 0) {
  console.error('❌ Validation Failed:');
  errors.forEach(e => console.error(e));
  process.exit(1);
} else {
  console.log('✅ All Schema Validations Passed!');
}
