interface PaginationProps {
  page: number;
  pageSize: number;
  totalCount: number;
  onPageChange: (page: number) => void;
}

export const Pagination: Component<PaginationProps> = (props) => {
  const totalPages = () => Math.max(1, Math.ceil(props.totalCount / props.pageSize));
  const from = () => props.totalCount === 0 ? 0 : (props.page - 1) * props.pageSize + 1;
  const to = () => Math.min(props.page * props.pageSize, props.totalCount);

  return (
    <div class="flex items-center justify-between px-4 py-3 bg-white border-t border-gray-200">
      <div class="text-sm text-gray-500">
        Showing <span class="font-medium">{from()}</span> to{' '}
        <span class="font-medium">{to()}</span> of{' '}
        <span class="font-medium">{props.totalCount}</span> results
      </div>
      <div class="flex space-x-2">
        <button
          class="btn btn-sm btn-secondary"
          disabled={props.page <= 1}
          onClick={() => props.onPageChange(props.page - 1)}
        >
          Previous
        </button>
        <span class="flex items-center px-3 text-sm text-gray-700">
          Page {props.page} of {totalPages()}
        </span>
        <button
          class="btn btn-sm btn-secondary"
          disabled={props.page >= totalPages()}
          onClick={() => props.onPageChange(props.page + 1)}
        >
          Next
        </button>
      </div>
    </div>
  );
};
