  columns: string[];
  editableColumns: string[];
  isEditable: boolean;
  primaryKey: string;
  totalCount: number;
  page: number;
  pageSize: number;
  sortColumn: string | null;
  sortDirection: SortDirection;
  onSort: (column: string) => void;
  onPageChange: (page: number) => void;
  onDataChange: () => void;
}

export const DataGrid: Component<DataGridProps> = (props) => {
  const [saving, setSaving] = createSignal<string | null>(null);
  const [saveError, setSaveError] = createSignal<string | null>(null);

  const isColumnEditable = (col: string) => {
    if (!props.isEditable) return false;
    if (col === props.primaryKey) return false;
    if (props.editableColumns.length === 0) return true; // all editable if none specified
    return props.editableColumns.includes(col);
  };

  const handleCellSave = async (rowId: string, column: string, newValue: unknown) => {
    setSaving(rowId + column);
    setSaveError(null);

    const { error } = await supabase
      .from(props.tableName)
      .update({ [column]: newValue })
      .eq(props.primaryKey, rowId);

    if (error) {
      setSaveError(`Failed to save: ${error.message}`);
    } else {
      props.onDataChange();
    }
    setSaving(null);
  };

  const sortIcon = (col: string) => {
    if (props.sortColumn !== col) return ' \u2195';
    return props.sortDirection === 'asc' ? ' \u2191' : ' \u2193';
  };

  return (
    <div class="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
      <Show when={saveError()}>
        <div class="bg-red-50 border-b border-red-200 px-4 py-2 text-sm text-red-700">
          {saveError()}
          <button class="ml-2 underline" onClick={() => setSaveError(null)}>dismiss</button>
        </div>
      </Show>

      <div class="overflow-x-auto">
        <table class="min-w-full divide-y divide-gray-200">
          <thead class="bg-gray-50">
            <tr>
              <For each={props.columns}>
                {(col) => (
                  <th
                    class="px-3 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer hover:bg-gray-100 select-none whitespace-nowrap"
                    onClick={() => props.onSort(col)}
                  >
                    {col}
                    <span class="text-gray-400">{sortIcon(col)}</span>
                  </th>
                )}
              </For>
            </tr>
          </thead>
          <tbody class="bg-white divide-y divide-gray-200">
            <Show when={props.data.length > 0} fallback={
              <tr>
                <td colspan={props.columns.length} class="px-4 py-8 text-center text-gray-400">
                  No data found
                </td>
              </tr>
            }>
              <For each={props.data}>
                {(row) => {
                  const rowId = String(row[props.primaryKey] ?? '');
                  return (
                    <tr class="hover:bg-gray-50">
                      <For each={props.columns}>
                        {(col) => (
                          <td class="text-sm text-gray-900 max-w-xs">
                            <EditableCell
                              value={row[col]}
                              editable={isColumnEditable(col)}
                              onSave={(v) => handleCellSave(rowId, col, v)}
                            />
                          </td>
