    f.write('''import { Component, createSignal, createEffect, Show, on } from 'solid-js';
import { supabase } from '../lib/supabase';
import { DataGrid } from '../components/DataGrid';
import { LoadingSpinner } from '../components/LoadingSpinner';
import type { PortalTableConfig, SortDirection } from '../lib/types';
import { VIEW_TABLES } from '../lib/types';

interface TableViewPageProps {
  tableName: string;
}

export const TableViewPage: Component<TableViewPageProps> = (props) => {
  const [config, setConfig] = createSignal<PortalTableConfig | null>(null);
  const [data, setData] = createSignal<Record<string, unknown>[]>([]);
  const [columns, setColumns] = createSignal<string[]>([]);
  const [primaryKey, setPrimaryKey] = createSignal('id');
  const [totalCount, setTotalCount] = createSignal(0);
  const [page, setPage] = createSignal(1);
  const [sortColumn, setSortColumn] = createSignal<string | null>(null);
  const [sortDirection, setSortDirection] = createSignal<SortDirection>('asc');
  const [loading, setLoading] = createSignal(true);
  const [error, setError] = createSignal<string | null>(null);
  const [refreshKey, setRefreshKey] = createSignal(0);

  const isView = () => (VIEW_TABLES as readonly string[]).includes(props.tableName);

  // Load config when tableName changes
  createEffect(on(() => props.tableName, async (tableName) => {
    setLoading(true);
    setError(null);
    setPage(1);
    setData([]);

    try {
      // Fetch portal config for this table
      const { data: cfgData, error: cfgErr } = await supabase
        .from('portal_table_config')
        .select('*')
        .eq('table_name', tableName)
        .single();

      if (cfgErr) {
        setError(`Table "${tableName}" is not configured for your organization.`);
        setLoading(false);
        return;
      }

      const cfg = cfgData as PortalTableConfig;
      setConfig(cfg);

      if (cfg.sort_column) {
        setSortColumn(cfg.sort_column);
        setSortDirection(cfg.sort_direction || 'asc');
      } else {
        setSortColumn(null);
        setSortDirection('asc');
      }

      // Discover columns by fetching one row
      const { data: sample } = await supabase
        .from(tableName)
        .select('*')
        .limit(1);

      if (sample && sample.length > 0) {
        let cols = Object.keys(sample[0]);

        // Apply hidden_columns filter
        if (cfg.hidden_columns && cfg.hidden_columns.length > 0) {
          cols = cols.filter(c => !cfg.hidden_columns.includes(c));
        }

        // Apply visible_columns filter (if specified, only show these)
        if (cfg.visible_columns && cfg.visible_columns.length > 0) {
          cols = cols.filter(c => cfg.visible_columns.includes(c));
        }

        // Apply column_order if specified
        if (cfg.column_order && cfg.column_order.length > 0) {
          const ordered = cfg.column_order.filter(c => cols.includes(c));
          const remaining = cols.filter(c => !ordered.includes(c));
          cols = [...ordered, ...remaining];
        }

        setColumns(cols);

        // Detect primary key (assume 'id' if present)
        if ('id' in sample[0]) {
          setPrimaryKey('id');
        } else {
          setPrimaryKey(cols[0]);
        }
      } else {
        // No data - try to get columns from an empty query
        setColumns([]);
      }
    } catch (e) {
      setError(String(e));
    }

    setLoading(false);
  }));

  // Fetch data when page, sort, or refreshKey changes
  createEffect(on(
    () => [page(), sortColumn(), sortDirection(), refreshKey(), config()] as const,
    async ([pg, sortCol, sortDir, _rk, cfg]) => {
      if (!cfg) return;

      const pageSize = cfg.page_size || 25;
      const from = (pg - 1) * pageSize;
      const to = from + pageSize - 1;

      let query = supabase
        .from(props.tableName)
        .select('*', { count: 'exact' })
        .range(from, to);

      if (sortCol) {
        query = query.order(sortCol, { ascending: sortDir === 'asc' });
      }

      const { data: rows, count, error: fetchErr } = await query;

      if (fetchErr) {
        setError(`Error fetching data: ${fetchErr.message}`);
      } else {
        setData((rows || []) as Record<string, unknown>[]);
        setTotalCount(count || 0);

        // If columns weren't set yet (empty table before), try now
        if (columns().length === 0 && rows && rows.length > 0) {
          let cols = Object.keys(rows[0]);
          if (cfg.hidden_columns?.length) {
            cols = cols.filter(c => !cfg.hidden_columns.includes(c));
          }
          if (cfg.visible_columns?.length) {
            cols = cols.filter(c => cfg.visible_columns.includes(c));
          }
          setColumns(cols);
        }
      }
    }
  ));

  const handleSort = (column: string) => {
    if (sortColumn() === column) {
      setSortDirection(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      setSortColumn(column);
      setSortDirection('asc');
    }
  };

  const handlePageChange = (newPage: number) => {
    setPage(newPage);
  };

  const handleDataChange = () => {
    setRefreshKey(k => k + 1);
  };

  const effectiveAccessLevel = () => {
    if (isView()) return 'readonly';
    return config()?.access_level || 'readonly';
  };

  return (
    <div>
      <div class="mb-6 flex items-center justify-between">
        <div>
          <h2 class="text-2xl font-bold text-gray-900">
            {config()?.display_name || props.tableName}
          </h2>
          <Show when={config()?.description}>
            <p class="mt-1 text-gray-500">{config()!.description}</p>
          </Show>
        </div>
        <div class="flex items-center space-x-3">
          <span class={`badge ${
            effectiveAccessLevel() === 'editable' ? 'badge-editable' : 'badge-readonly'
          }`}>
            {effectiveAccessLevel() === 'editable' ? 'Editable' : 'Read Only'}
          </span>
          <Show when={isView()}>
            <span class="badge bg-purple-100 text-purple-800">View</span>
          </Show>
          <button
            class="btn btn-sm btn-secondary"
            onClick={handleDataChange}
          >
            \u21BB Refresh
          </button>
        </div>
      </div>

      <Show when={error()}>
        <div class="card bg-red-50 border-red-200 mb-4">
          <p class="text-red-700">{error()}</p>
        </div>
      </Show>

      <Show when={!loading()} fallback={<LoadingSpinner />}>
        <Show when={columns().length > 0} fallback={
          <div class="card text-center py-12">
            <p class="text-gray-400">No data available for this table</p>
          </div>
        }>
          <DataGrid
            tableName={props.tableName}
            data={data()}
            columns={columns()}
            editableColumns={config()?.editable_columns || []}
            isEditable={effectiveAccessLevel() === 'editable'}
            primaryKey={primaryKey()}
            totalCount={totalCount()}
            page={page()}
            pageSize={config()?.page_size || 25}
            sortColumn={sortColumn()}
            sortDirection={sortDirection()}
            onSort={handleSort}
            onPageChange={handlePageChange}
            onDataChange={handleDataChange}
          />
        </Show>
      </Show>
    </div>
  );
};
''')

