    f.write('''import { Component, createSignal, createResource, For, Show, createEffect } from 'solid-js';
import { supabaseAdmin } from '../lib/supabase';
import { LoadingSpinner } from '../components/LoadingSpinner';
import { ALL_TABLES, VIEW_TABLES } from '../lib/types';
import type { PortalTableConfig } from '../lib/types';

interface OrgOption {
  id: string;
  name: string;
  slug: string;
}

interface TableConfigRow {
  table_name: string;
  display_name: string;
  access_level: 'hidden' | 'readonly' | 'editable';
  editable_columns: string[];
  hidden_columns: string[];
  visible_columns: string[];
  page_size: number;
  display_order: number;
  description: string;
  existing_id: string | null;
  dirty: boolean;
  availableColumns: string[];
}

export const AdminConfigPage: Component = () => {
  const [selectedOrg, setSelectedOrg] = createSignal<string>('');
  const [configs, setConfigs] = createSignal<TableConfigRow[]>([]);
  const [saving, setSaving] = createSignal(false);
  const [saveMsg, setSaveMsg] = createSignal<{ type: 'success' | 'error'; text: string } | null>(null);

  // Fetch all organizations (admin bypasses RLS)
  const [orgs] = createResource(async () => {
    const { data, error } = await supabaseAdmin
      .from('organizations')
      .select('id, name, slug')
      .order('name');
    if (error) throw error;
    return (data || []) as OrgOption[];
  });

  // Discover columns for a table
  const discoverColumns = async (tableName: string): Promise<string[]> => {
    const { data } = await supabaseAdmin
      .from(tableName)
      .select('*')
      .limit(1);
    if (data && data.length > 0) return Object.keys(data[0]);
    return [];
  };

  // Load config when org changes
  createEffect(async () => {
    const orgId = selectedOrg();
    if (!orgId) {
      setConfigs([]);
      return;
    }

    // Fetch existing configs for this org
    const { data: existing } = await supabaseAdmin
      .from('portal_table_config')
      .select('*')
      .eq('organization_id', orgId);

    const existingMap = new Map<string, PortalTableConfig>();
    (existing || []).forEach((c: PortalTableConfig) => existingMap.set(c.table_name, c));

    // Build config rows for all tables
    const rows: TableConfigRow[] = [];
    for (const tableName of ALL_TABLES) {
      const ex = existingMap.get(tableName);
      const cols = await discoverColumns(tableName);

      rows.push({
        table_name: tableName,
        display_name: ex?.display_name || tableName.replace(/_/g, ' ').replace(/\\bv\\b/g, '').replace(/^\\w/, c => c.toUpperCase()),
        access_level: ex?.access_level || 'hidden',
        editable_columns: ex?.editable_columns || [],
        hidden_columns: ex?.hidden_columns || [],
        visible_columns: ex?.visible_columns || [],
        page_size: ex?.page_size || 25,
        display_order: ex?.display_order || 0,
        description: ex?.description || '',
        existing_id: ex?.id || null,
        dirty: false,
        availableColumns: cols,
      });
    }

    setConfigs(rows);
  });

  const updateConfig = (tableName: string, field: string, value: unknown) => {
    setConfigs(prev => prev.map(c =>
      c.table_name === tableName
        ? { ...c, [field]: value, dirty: true }
        : c
    ));
  };

  const toggleColumn = (tableName: string, field: 'editable_columns' | 'hidden_columns', col: string) => {
    setConfigs(prev => prev.map(c => {
      if (c.table_name !== tableName) return c;
      const arr = [...c[field]];
      const idx = arr.indexOf(col);
      if (idx >= 0) arr.splice(idx, 1);
      else arr.push(col);
      return { ...c, [field]: arr, dirty: true };
    }));
  };

  const saveAll = async () => {
    setSaving(true);
    setSaveMsg(null);
    const orgId = selectedOrg();
    let errorCount = 0;

    for (const cfg of configs()) {
      if (!cfg.dirty) continue;

      const payload = {
        organization_id: orgId,
        table_name: cfg.table_name,
        display_name: cfg.display_name,
        access_level: cfg.access_level,
        editable_columns: cfg.editable_columns,
        hidden_columns: cfg.hidden_columns,
        visible_columns: cfg.visible_columns,
        page_size: cfg.page_size,
        display_order: cfg.display_order,
        description: cfg.description,
      };

      if (cfg.existing_id) {
        const { error } = await supabaseAdmin
          .from('portal_table_config')
          .update(payload)
          .eq('id', cfg.existing_id);
        if (error) errorCount++;
      } else {
        const { error } = await supabaseAdmin
          .from('portal_table_config')
          .insert(payload);
        if (error) errorCount++;
      }
    }

    if (errorCount > 0) {
      setSaveMsg({ type: 'error', text: `${errorCount} table(s) failed to save` });
    } else {
      setSaveMsg({ type: 'success', text: 'All changes saved successfully' });
      // Mark all as clean
      setConfigs(prev => prev.map(c => ({ ...c, dirty: false })));
    }
    setSaving(false);
  };

  const dirtyCount = () => configs().filter(c => c.dirty).length;
  const isView = (name: string) => (VIEW_TABLES as readonly string[]).includes(name);

  return (
    <div>
      <div class="mb-6">
        <h2 class="text-2xl font-bold text-gray-900">Admin Configuration</h2>
        <p class="mt-1 text-gray-500">Configure which tables each organization can access</p>
      </div>

      {/* Org selector */}
      <div class="card mb-6">
        <label class="block text-sm font-medium text-gray-700 mb-2">Organization</label>
        <Show when={!orgs.loading} fallback={<LoadingSpinner size="h-5 w-5" />}>
          <select
            class="input max-w-md"
            value={selectedOrg()}
            onChange={(e) => setSelectedOrg(e.currentTarget.value)}
          >
            <option value="">Select an organization...</option>
            <For each={orgs()}>
              {(org) => <option value={org.id}>{org.name} ({org.slug})</option>}
            </For>
          </select>
        </Show>
      </div>

      <Show when={selectedOrg() && configs().length > 0}>
        {/* Save bar */}
        <div class="sticky top-0 z-10 bg-gray-50 border-b border-gray-200 px-4 py-3 mb-4 flex items-center justify-between rounded-lg">
          <div>
            <Show when={dirtyCount() > 0}>
              <span class="text-sm text-amber-600 font-medium">
                {dirtyCount()} unsaved change(s)
              </span>
            </Show>
            <Show when={saveMsg()}>
              <span class={`text-sm ml-4 ${
                saveMsg()!.type === 'success' ? 'text-green-600' : 'text-red-600'
              }`}>
                {saveMsg()!.text}
              </span>
            </Show>
          </div>
          <button
            class="btn btn-primary"
            disabled={saving() || dirtyCount() === 0}
            onClick={saveAll}
          >
            {saving() ? 'Saving...' : 'Save All Changes'}
          </button>
        </div>

        {/* Table configs */}
        <div class="space-y-4">
          <For each={configs()}>
            {(cfg) => (
              <div class={`card ${
                cfg.dirty ? 'border-amber-300 bg-amber-50/30' : ''
              }`}>
                <div class="flex items-start justify-between mb-4">
                  <div class="flex-1">
                    <div class="flex items-center space-x-2">
                      <h3 class="text-lg font-semibold text-gray-900">{cfg.table_name}</h3>
                      <Show when={isView(cfg.table_name)}>
                        <span class="badge bg-purple-100 text-purple-800">View</span>
                      </Show>
                    </div>
                    <input
                      class="input mt-1 max-w-sm"
                      value={cfg.display_name}
                      onInput={(e) => updateConfig(cfg.table_name, 'display_name', e.currentTarget.value)}
                      placeholder="Display name"
                    />
                  </div>

                  {/* Access level selector */}
                  <div class="ml-4">
                    <label class="block text-xs font-medium text-gray-500 mb-1">Access Level</label>
                    <select
                      class="input w-36"
                      value={cfg.access_level}
                      onChange={(e) => updateConfig(cfg.table_name, 'access_level', e.currentTarget.value)}
                    >
                      <option value="hidden">Hidden</option>
                      <option value="readonly">Read Only</option>
                      <option value="editable" disabled={isView(cfg.table_name)}>Editable</option>
                    </select>
                  </div>
                </div>

                {/* Description */}
                <div class="mb-4">
                  <label class="block text-xs font-medium text-gray-500 mb-1">Description</label>
                  <input
                    class="input"
                    value={cfg.description}
                    onInput={(e) => updateConfig(cfg.table_name, 'description', e.currentTarget.value)}
                    placeholder="Help text shown to tenant"
                  />
                </div>

                {/* Settings row */}
                <div class="flex items-center space-x-4 mb-4">
                  <div>
                    <label class="block text-xs font-medium text-gray-500 mb-1">Page Size</label>
                    <input
                      type="number"
                      class="input w-20"
                      value={cfg.page_size}
                      onInput={(e) => updateConfig(cfg.table_name, 'page_size', parseInt(e.currentTarget.value) || 25)}
                      min="5"
                      max="100"
                    />
                  </div>
                  <div>
                    <label class="block text-xs font-medium text-gray-500 mb-1">Display Order</label>
                    <input
                      type="number"
                      class="input w-20"
                      value={cfg.display_order}
                      onInput={(e) => updateConfig(cfg.table_name, 'display_order', parseInt(e.currentTarget.value) || 0)}
                    />
                  </div>
                </div>

                {/* Column config - only show if not hidden */}
                <Show when={cfg.access_level !== 'hidden' && cfg.availableColumns.length > 0}>
                  <div class="border-t border-gray-200 pt-4">
                    <p class="text-xs font-medium text-gray-500 mb-2">Columns</p>
                    <div class="flex flex-wrap gap-2">
                      <For each={cfg.availableColumns}>
                        {(col) => {
                          const isHidden = cfg.hidden_columns.includes(col);
                          const isEditable = cfg.editable_columns.includes(col);
                          return (
                            <div class={`flex items-center space-x-1 px-2 py-1 rounded border text-xs ${
                              isHidden
                                ? 'bg-gray-100 border-gray-300 text-gray-400 line-through'
                                : isEditable
                                  ? 'bg-green-50 border-green-300 text-green-800'
                                  : 'bg-white border-gray-200 text-gray-700'
                            }`}>
                              <span>{col}</span>
                              <button
                                class="text-gray-400 hover:text-red-500"
                                title={isHidden ? 'Show column' : 'Hide column'}
                                onClick={() => toggleColumn(cfg.table_name, 'hidden_columns', col)}
                              >
                                {isHidden ? '\u25CB' : '\u25CF'}
                              </button>
                              <Show when={cfg.access_level === 'editable' && !isHidden}>
                                <button
                                  class={`${
                                    isEditable ? 'text-green-600' : 'text-gray-300 hover:text-green-500'
                                  }`}
                                  title={isEditable ? 'Make read-only' : 'Make editable'}
                                  onClick={() => toggleColumn(cfg.table_name, 'editable_columns', col)}
                                >
                                  \u270E
                                </button>
                              </Show>
                            </div>
                          );
                        }}
                      </For>
                    </div>
                    <p class="text-xs text-gray-400 mt-2">
                      \u25CF visible &nbsp; \u25CB hidden &nbsp;
                      <Show when={cfg.access_level === 'editable'}>
                        \u270E editable (green = editable, empty = all editable)
                      </Show>
                    </p>
                  </div>
                </Show>
              </div>
            )}
          </For>
        </div>
      </Show>
    </div>
  );
};
