CREATE OR REPLACE FUNCTION create_work_order_atomic(
    p_unit_id UUID,
    p_template_id UUID,
    p_assigned_contractor_id UUID DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
AS $$
DECLARE
    v_template   work_order_templates%ROWTYPE;
    v_unit       units%ROWTYPE;
    v_wo_id      UUID;
    v_rooms      RECORD;
    v_task_count INT := 0;
BEGIN
    -- All operations inside this function are a single transaction
    -- If anything fails, everything rolls back automatically

    SELECT * INTO STRICT v_template
    FROM work_order_templates WHERE id = p_template_id AND is_active = true;

    SELECT * INTO STRICT v_unit
    FROM units WHERE id = p_unit_id;

    INSERT INTO work_orders (organization_id, unit_id, template_id, trade_name,
                             assigned_contractor_id, status)
    VALUES (v_unit.organization_id, p_unit_id, p_template_id,
            v_template.trade_name, p_assigned_contractor_id, 'pending')
    RETURNING id INTO v_wo_id;

    -- Insert tasks for each room (unit-specific first, then org fallback)
    INSERT INTO work_order_tasks (work_order_id, room_id, row_order, task_data)
    SELECT v_wo_id, r.id, ROW_NUMBER() OVER (ORDER BY r.display_order) - 1,
           jsonb_build_object('steps', /* build from template definition */
               (SELECT jsonb_agg(step) FROM (
                   SELECT jsonb_build_object(
                       'key', col->>'key',
                       'label', col->>'label',
                       'status', 'pending',
                       'not_applicable', COALESCE((col->>'default_na')::boolean, false)
                   ) AS step
                   FROM jsonb_each(v_template.definition->'sections') AS s(k,v),
                        jsonb_array_elements(v->'columns') AS col
               ) sub)
           )
    FROM (
        SELECT rooms.* FROM unit_rooms
        JOIN rooms ON rooms.id = unit_rooms.room_id
        WHERE unit_rooms.unit_id = p_unit_id
        UNION ALL
        SELECT rooms.* FROM rooms
        WHERE rooms.organization_id = v_unit.organization_id
          AND NOT EXISTS (SELECT 1 FROM unit_rooms WHERE unit_id = p_unit_id)
    ) r;

    GET DIAGNOSTICS v_task_count = ROW_COUNT;

    IF v_task_count = 0 THEN
        RAISE EXCEPTION 'No rooms available — cannot create tasks'
            USING ERRCODE = 'P0002';
    END IF;

    RETURN jsonb_build_object(
        'id', v_wo_id,
        'task_count', v_task_count
    );

EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RAISE EXCEPTION 'Referenced template or unit does not exist'
            USING ERRCODE = 'P0002';
END;
$$;
