/**
 * Suggest room names based on unit metadata.
 * Uses bedroom count as primary heuristic, falls back to area-based estimation.
 */
export function suggestRoomNames(unit: UnitInfo): string[] {
  if (unit.bedrooms !== null && unit.bedrooms !== undefined) {
    if (unit.bedrooms === 0) return DEFAULT_ROOM_SETS.studio;
    if (unit.bedrooms === 1) return DEFAULT_ROOM_SETS['1bed'];
    if (unit.bedrooms === 2) return DEFAULT_ROOM_SETS['2bed'];
    if (unit.bedrooms === 3) return DEFAULT_ROOM_SETS['3bed'];
    if (unit.bedrooms >= 4) return DEFAULT_ROOM_SETS['4bed'];
  }

  // Area-based estimation fallback
  if (unit.area_sf) {
    if (unit.area_sf < 500) return DEFAULT_ROOM_SETS.studio;
    if (unit.area_sf < 800) return DEFAULT_ROOM_SETS['1bed'];
    if (unit.area_sf < 1200) return DEFAULT_ROOM_SETS['2bed'];
    if (unit.area_sf < 1600) return DEFAULT_ROOM_SETS['3bed'];
    return DEFAULT_ROOM_SETS['4bed'];
  }

  return DEFAULT_ROOM_SETS.default;
}

/**
 * Build insertable room records from suggested names.
 */
export function buildDraftRooms(unit: UnitInfo, reason: string): GeneratedRoom[] {
  const names = suggestRoomNames(unit);
  return names.map((name, index) => ({
    organization_id: unit.organization_id,
    name,
    display_order: index,
    status: 'draft' as const,
    auto_generated: true,
    generation_source: 'system_placeholder' as const,
    generation_metadata: {
      reason,
      based_on: {
        unit_id: unit.id,
        bedrooms: unit.bedrooms,
        area_sf: unit.area_sf,
        unit_type: unit.unit_type,
      },
    },
  }));
}

