export interface GeneratedTemplate {
  organization_id: string;
  trade_name: string;
  version: number;
  is_active: boolean;
  status: 'draft';
  auto_generated: boolean;
  generation_source: 'system_placeholder';
  generation_metadata: Record<string, unknown>;
  definition: TemplateDefinition;
  scope: 'company';
}

/**
 * Get a suggested template definition for a given trade name.
 * Tries exact match first, then case-insensitive, then generic fallback.
 */
export function suggestTemplateDefinition(tradeName: string): TemplateDefinition {
  // Exact match
  if (DEFAULT_TEMPLATE_DEFINITIONS[tradeName]) {
    return DEFAULT_TEMPLATE_DEFINITIONS[tradeName];
  }
  // Case-insensitive match
  const lower = tradeName.toLowerCase();
  for (const [key, def] of Object.entries(DEFAULT_TEMPLATE_DEFINITIONS)) {
    if (key.toLowerCase() === lower) return def;
  }
  // Partial match (e.g., "Interior Painting" matches "Painting")
  for (const [key, def] of Object.entries(DEFAULT_TEMPLATE_DEFINITIONS)) {
    if (key === '_generic') continue;
    if (lower.includes(key.toLowerCase()) || key.toLowerCase().includes(lower)) {
      return def;
    }
  }
  return DEFAULT_TEMPLATE_DEFINITIONS._generic;
}

/**
 * Build an insertable draft template record.
 */
export function buildDraftTemplate(
  organizationId: string,
  tradeName: string,
  reason: string
): GeneratedTemplate {
  const definition = suggestTemplateDefinition(tradeName);
  return {
    organization_id: organizationId,
    trade_name: tradeName,
    version: 1,
    is_active: true,
    status: 'draft',
    auto_generated: true,
    generation_source: 'system_placeholder',
    generation_metadata: {
      reason,
      matched_trade: tradeName,
      is_generic: definition === DEFAULT_TEMPLATE_DEFINITIONS._generic,
    },
    definition,
    scope: 'company',
  };
}

// --- Similarity Search ---

/**
 * Try to find an existing template for the same trade in the organization.
 * Returns the best match or null.
 */
export async function findSimilarTemplate(
  supabase: SupabaseClient,
  organizationId: string,
  tradeName: string
): Promise<{ id: string; trade_name: string; status: string } | null> {
  const { data } = await supabase
    .from('work_order_templates')
    .select('id, trade_name, status')
    .eq('organization_id', organizationId)
    .eq('is_active', true)
    .ilike('trade_name', `%${tradeName}%`)
    .limit(1)
    .single();
  return data;
}

