 */
export async function createReviewsBatch(
  supabase: SupabaseClient,
  inputs: CreateReviewInput[]
): Promise<PendingReview[]> {
  if (inputs.length === 0) return [];

  const { data, error } = await supabase
    .from('pending_reviews')
    .insert(inputs)
    .select();

  if (error) {
    console.error('[ReviewService] Failed to create batch reviews:', error.message);
    return [];
  }
  return data || [];
}

/**
 * List pending reviews with optional filters.
 */
export async function listReviews(
  supabase: SupabaseClient,
  filters: {
    organization_id?: string;
    status?: string;
    entity_type?: string;
    trigger_entity_id?: string;
    limit?: number;
    offset?: number;
  } = {}
): Promise<{ data: PendingReview[]; count: number }> {
  let query = supabase
    .from('pending_reviews')
    .select('*', { count: 'exact' })
    .order('created_at', { ascending: false });

  if (filters.organization_id) query = query.eq('organization_id', filters.organization_id);
  if (filters.status) query = query.eq('status', filters.status);
  if (filters.entity_type) query = query.eq('entity_type', filters.entity_type);
  if (filters.trigger_entity_id) query = query.eq('trigger_entity_id', filters.trigger_entity_id);
  if (filters.limit) query = query.limit(filters.limit);
  if (filters.offset) query = query.range(filters.offset, filters.offset + (filters.limit || 20) - 1);

  const { data, error, count } = await query;

  if (error) {
    console.error('[ReviewService] Failed to list reviews:', error.message);
    return { data: [], count: 0 };
  }
  return { data: data || [], count: count || 0 };
}

/**
 * Get a single review by ID.
 */
export async function getReview(
  supabase: SupabaseClient,
  reviewId: string
): Promise<PendingReview | null> {
  const { data, error } = await supabase
    .from('pending_reviews')
    .select('*')
    .eq('id', reviewId)
    .single();

  if (error) return null;
  return data;
}

/**
 * Approve a review: sets entity status to 'active', marks review as approved.
 * Also checks if all reviews for a related work order are resolved.
 */
export async function approveReview(
  supabase: SupabaseClient,
  reviewId: string,
  reviewerId: string,
  notes?: string
): Promise<{ success: boolean; error?: string }> {
  // 1. Get the review
  const review = await getReview(supabase, reviewId);
  if (!review) return { success: false, error: 'Review not found' };
  if (review.status !== 'pending') return { success: false, error: `Review is already ${review.status}` };

  // 2. Update the entity status to 'active'
  const entityTable = getEntityTable(review.entity_type);
  if (entityTable) {
    const { error: entityError } = await supabase
      .from(entityTable)
      .update({ status: 'active' })
      .eq('id', review.entity_id);

    if (entityError) {
      return { success: false, error: `Failed to activate entity: ${entityError.message}` };
    }
  }

  // 3. Mark review as approved
  const { error: reviewError } = await supabase
    .from('pending_reviews')
    .update({
      status: 'approved',
      reviewer_id: reviewerId,
      reviewed_at: new Date().toISOString(),
      review_notes: notes || null,
    })
    .eq('id', reviewId);

  if (reviewError) {
    return { success: false, error: `Failed to update review: ${reviewError.message}` };
  }

  // 4. Check if all reviews for the trigger work order are resolved
  if (review.trigger_entity_id) {
    await maybePromoteWorkOrder(supabase, review.trigger_entity_id);
  }

  return { success: true };
}

/**
 * Reject a review: archives the entity, marks review as rejected.
 */
export async function rejectReview(
  supabase: SupabaseClient,
  reviewId: string,
  reviewerId: string,
  notes?: string
): Promise<{ success: boolean; error?: string }> {
  const review = await getReview(supabase, reviewId);
  if (!review) return { success: false, error: 'Review not found' };
  if (review.status !== 'pending') return { success: false, error: `Review is already ${review.status}` };

  // Archive the entity (don't delete - keep for audit)
  const entityTable = getEntityTable(review.entity_type);
  if (entityTable) {
    await supabase
      .from(entityTable)
      .update({ status: 'archived', is_active: false })
      .eq('id', review.entity_id);
  }

  // Mark review as rejected
  const { error } = await supabase
    .from('pending_reviews')
    .update({
      status: 'rejected',
      reviewer_id: reviewerId,
      reviewed_at: new Date().toISOString(),
      review_notes: notes || null,
    })
    .eq('id', reviewId);

  if (error) return { success: false, error: error.message };
  return { success: true };
}

/**
 * Replace a review: update entity with user-provided data, mark as replaced.
 * If the entity is a template, re-generate work order tasks.
 */
export async function replaceReview(
  supabase: SupabaseClient,
  reviewId: string,
  reviewerId: string,
  replacementData: Record<string, unknown>,
  notes?: string
): Promise<{ success: boolean; error?: string }> {
  const review = await getReview(supabase, reviewId);
  if (!review) return { success: false, error: 'Review not found' };
  if (review.status !== 'pending') return { success: false, error: `Review is already ${review.status}` };

  // Update the entity with replacement data + set active
  const entityTable = getEntityTable(review.entity_type);
  if (entityTable) {
    const updatePayload = {
      ...replacementData,
      status: 'active',
      auto_generated: false, // User has now manually provided data
    };

    const { error: entityError } = await supabase
      .from(entityTable)
      .update(updatePayload)
      .eq('id', review.entity_id);

    if (entityError) {
      return { success: false, error: `Failed to update entity: ${entityError.message}` };
    }
  }

  // If template was replaced and there's a trigger WO, regenerate tasks
  if (review.entity_type === 'work_order_template' && review.trigger_entity_id) {
    await regenerateWorkOrderTasks(supabase, review.trigger_entity_id, review.entity_id);
  }

  // Mark review as replaced
  const { error } = await supabase
    .from('pending_reviews')
    .update({
      status: 'replaced',
      reviewer_id: reviewerId,
      reviewed_at: new Date().toISOString(),
      review_notes: notes || null,
      replacement_data: replacementData,
    })
    .eq('id', reviewId);

  if (error) return { success: false, error: error.message };

  // Check if all reviews for the trigger WO are resolved
  if (review.trigger_entity_id) {
    await maybePromoteWorkOrder(supabase, review.trigger_entity_id);
  }

  return { success: true };
}

/**
 * Get review summary counts for dashboard badge.
 */
export async function getReviewSummary(
  supabase: SupabaseClient,
  organizationId: string
): Promise<ReviewSummary> {
  const { data, error } = await supabase
    .from('pending_reviews')
    .select('entity_type, created_at')
    .eq('organization_id', organizationId)
    .eq('status', 'pending')
    .order('created_at', { ascending: true });

  if (error || !data) {
    return { total_pending: 0, by_type: {} };
  }

  const by_type: Record<string, number> = {};
  for (const row of data) {
    by_type[row.entity_type] = (by_type[row.entity_type] || 0) + 1;
  }

  return {
    total_pending: data.length,
    by_type,
    oldest_pending: data.length > 0 ? data[0].created_at : undefined,
  };
}

// --- Internal Helpers ---

function getEntityTable(entityType: string): string | null {
  switch (entityType) {
    case 'work_order_template': return 'work_order_templates';
    case 'room': return 'rooms';
    case 'work_order': return 'work_orders';
    case 'unit': return 'units';
    default: return null;
  }
}

/**
 * If all pending reviews for a work order are resolved,
 * promote the WO from 'needs_review' to 'pending'.
 */
async function maybePromoteWorkOrder(
  supabase: SupabaseClient,
  workOrderId: string
): Promise<void> {
  const { data: remaining } = await supabase
    .from('pending_reviews')
    .select('id')
    .eq('trigger_entity_id', workOrderId)
    .eq('status', 'pending');

  if (!remaining || remaining.length === 0) {
    // All reviews resolved - promote WO
    await supabase
      .from('work_orders')
      .update({ status: 'pending' })
      .eq('id', workOrderId)
      .eq('status', 'needs_review');

    console.log(`[ReviewService] All reviews resolved for WO ${workOrderId}, promoted to pending`);
  }
}

/**
 * Regenerate work order tasks when a template is replaced.
 * Deletes old tasks and creates new ones from the updated template.
 */
async function regenerateWorkOrderTasks(
  supabase: SupabaseClient,
  workOrderId: string,
  templateId: string
): Promise<void> {
  // Get the updated template
  const { data: template } = await supabase
    .from('work_order_templates')
    .select('definition')
    .eq('id', templateId)
    .single();

  if (!template) return;

  // Get existing tasks to preserve room assignments
  const { data: existingTasks } = await supabase
    .from('work_order_tasks')
    .select('room_id, row_order')
    .eq('work_order_id', workOrderId)
    .order('row_order', { ascending: true });

  if (!existingTasks || existingTasks.length === 0) return;

  // Delete old tasks
  await supabase
    .from('work_order_tasks')
    .delete()
    .eq('work_order_id', workOrderId);

  // Create new tasks with updated template definition
  const newTasks = existingTasks.map((task, index) => ({
    work_order_id: workOrderId,
    room_id: task.room_id,
    row_order: index,
    task_data: {
      steps: Object.values(template.definition.sections).flatMap((section: any) =>
        section.columns.map((col: any) => ({
          key: col.key,
          label: col.label,
          status: 'pending',
          not_applicable: col.default_na || false,
        }))
      ),
    },
  }));

  await supabase.from('work_order_tasks').insert(newTasks);
  console.log(`[ReviewService] Regenerated ${newTasks.length} tasks for WO ${workOrderId}`);
}
